import json

def load_trajectories(path: str):
    entries = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            if line.strip():
                entries.append(json.loads(line))
    return entries

successful = [e for e in load_trajectories("trajectory_samples.jsonl") if e.get("completed")]
